// Cloudflare Worker with SendGrid and Stripe Integration

const ALLOWED_ORIGINS = ['https://yourdomain.com', 'https://www.yourdomain.com'];

const RATE_LIMIT_WINDOW = 60000;
const RATE_LIMIT_MAX_REQUESTS = 100;

class RateLimiter {
  constructor(maxRequests, windowMs) {
    this.maxRequests = maxRequests;
    this.windowMs = windowMs;
  }

  async isRateLimited(ip, env) {
    const key = `rate_limit:${ip}`;
    const now = Date.now();
    const windowStart = now - this.windowMs;

    let requests = await env.RATE_LIMITER.get(key, { type: 'json' }) || [];
    requests = requests.filter(timestamp => timestamp > windowStart);

    if (requests.length >= this.maxRequests) {
      return true;
    }

    requests.push(now);
    await env.RATE_LIMITER.put(key, JSON.stringify(requests), {
      expirationTtl: Math.ceil(this.windowMs / 1000)
    });

    return false;
  }
}

class SecurityValidator {
  static validateInput(data, schema) {
    for (const [key, rules] of Object.entries(schema)) {
      const value = data[key];

      if (rules.required && !value) {
        throw new Error(`Missing required field: ${key}`);
      }

      if (value && rules.type && typeof value !== rules.type) {
        throw new Error(`Invalid type for ${key}: expected ${rules.type}`);
      }

      if (value && rules.pattern && !rules.pattern.test(value)) {
        throw new Error(`Invalid format for ${key}`);
      }

      if (value && rules.maxLength && value.length > rules.maxLength) {
        throw new Error(`${key} exceeds maximum length`);
      }

      if (value && rules.minLength && value.length < rules.minLength) {
        throw new Error(`${key} below minimum length`);
      }
    }
  }

  static sanitizeString(str) {
    return str.replace(/[<>\"'&]/g, char => {
      const entities = {
        '<': '&lt;',
        '>': '&gt;',
        '"': '&quot;',
        "'": '&#x27;',
        '&': '&amp;'
      };
      return entities[char];
    });
  }

  static validateEmail(email) {
    const emailRegex = /^[^\s@]+@[^\s@]+\.[^\s@]+$/;
    return emailRegex.test(email);
  }

  static validateAmount(amount) {
    return typeof amount === 'number' && amount > 0 && amount < 1000000000;
  }
}

class SendGridService {
  constructor(apiKey) {
    this.apiKey = apiKey;
    this.baseUrl = 'https://api.sendgrid.com/v3';
  }

  async sendEmail(to, subject, content) {
    if (!SecurityValidator.validateEmail(to)) {
      throw new Error('Invalid email address');
    }

    const payload = {
      personalizations: [{
        to: [{ email: to }],
        subject: SecurityValidator.sanitizeString(subject)
      }],
      from: { email: 'noreply@yourdomain.com', name: 'Your Service' },
      content: [{
        type: 'text/html',
        value: SecurityValidator.sanitizeString(content)
      }]
    };

    const response = await fetch(`${this.baseUrl}/mail/send`, {
      method: 'POST',
      headers: {
        'Authorization': `Bearer ${this.apiKey}`,
        'Content-Type': 'application/json'
      },
      body: JSON.stringify(payload)
    });

    if (!response.ok) {
      const error = await response.text();
      throw new Error(`SendGrid API error: ${response.status} - ${error}`);
    }

    return { success: true, messageId: response.headers.get('X-Message-Id') };
  }
}

class StripeService {
  constructor(apiKey) {
    this.apiKey = apiKey;
    this.baseUrl = 'https://api.stripe.com/v1';
  }

  async createPaymentIntent(amount, currency, metadata = {}) {
    if (!SecurityValidator.validateAmount(amount)) {
      throw new Error('Invalid payment amount');
    }

    const params = new URLSearchParams({
      amount: Math.round(amount * 100),
      currency: currency || 'usd',
      'metadata[source]': 'cloudflare_worker'
    });

    for (const [key, value] of Object.entries(metadata)) {
      params.append(`metadata[${key}]`, SecurityValidator.sanitizeString(String(value)));
    }

    const response = await fetch(`${this.baseUrl}/payment_intents`, {
      method: 'POST',
      headers: {
        'Authorization': `Bearer ${this.apiKey}`,
        'Content-Type': 'application/x-www-form-urlencoded'
      },
      body: params.toString()
    });

    if (!response.ok) {
      const error = await response.json();
      throw new Error(`Stripe API error: ${error.error?.message || response.statusText}`);
    }

    return await response.json();
  }

  async retrievePaymentIntent(paymentIntentId) {
    const response = await fetch(`${this.baseUrl}/payment_intents/${paymentIntentId}`, {
      method: 'GET',
      headers: {
        'Authorization': `Bearer ${this.apiKey}`
      }
    });

    if (!response.ok) {
      const error = await response.json();
      throw new Error(`Stripe API error: ${error.error?.message || response.statusText}`);
    }

    return await response.json();
  }

  async createCustomer(email, name, metadata = {}) {
    if (!SecurityValidator.validateEmail(email)) {
      throw new Error('Invalid email address');
    }

    const params = new URLSearchParams({
      email: email,
      name: SecurityValidator.sanitizeString(name)
    });

    for (const [key, value] of Object.entries(metadata)) {
      params.append(`metadata[${key}]`, SecurityValidator.sanitizeString(String(value)));
    }

    const response = await fetch(`${this.baseUrl}/customers`, {
      method: 'POST',
      headers: {
        'Authorization': `Bearer ${this.apiKey}`,
        'Content-Type': 'application/x-www-form-urlencoded'
      },
      body: params.toString()
    });

    if (!response.ok) {
      const error = await response.json();
      throw new Error(`Stripe API error: ${error.error?.message || response.statusText}`);
    }

    return await response.json();
  }
}

class APIKeyValidator {
  static async validateAPIKey(request, env) {
    const apiKey = request.headers.get('X-API-Key');
    
    if (!apiKey) {
      throw new Error('Missing API key');
    }

    const validKeys = await env.API_KEYS.get('valid_keys', { type: 'json' }) || [];
    
    if (!validKeys.includes(apiKey)) {
      throw new Error('Invalid API key');
    }

    return true;
  }

  static async validateWebhookSignature(request, env, service) {
    const signature = request.headers.get('stripe-signature') || request.headers.get('x-twilio-email-event-webhook-signature');
    
    if (!signature) {
      throw new Error('Missing webhook signature');
    }

    return true;
  }
}

function corsHeaders(origin) {
  const allowedOrigin = ALLOWED_ORIGINS.includes(origin) ? origin : ALLOWED_ORIGINS[0];
  
  return {
    'Access-Control-Allow-Origin': allowedOrigin,
    'Access-Control-Allow-Methods': 'GET, POST, OPTIONS',
    'Access-Control-Allow-Headers': 'Content-Type, X-API-Key, Authorization',
    'Access-Control-Max-Age': '86400',
    'X-Content-Type-Options': 'nosniff',
    'X-Frame-Options': 'DENY',
    'X-XSS-Protection': '1; mode=block',
    'Strict-Transport-Security': 'max-age=31536000; includeSubDomains',
    'Content-Security-Policy': "default-src 'none'; frame-ancestors 'none'"
  };
}

function jsonResponse(data, status = 200, origin = '') {
  return new Response(JSON.stringify(data), {
    status,
    headers: {
      'Content-Type': 'application/json',
      ...corsHeaders(origin)
    }
  });
}

function errorResponse(message, status = 400, origin = '') {
  return jsonResponse({ error: message, success: false }, status, origin);
}

async function handleSendEmail(request, env, origin) {
  const data = await request.json();

  SecurityValidator.validateInput(data, {
    to: { required: true, type: 'string', pattern: /^[^\s@]+@[^\s@]+\.[^\s@]+$/ },
    subject: { required: true, type: 'string', maxLength: 200 },
    content: { required: true, type: 'string', maxLength: 50000 }
  });

  const sendGrid = new SendGridService(env.SENDGRID_API_KEY);
  const result = await sendGrid.sendEmail(data.to, data.subject, data.content);

  return jsonResponse({ success: true, data: result }, 200, origin);
}

async function handleCreatePayment(request, env, origin) {
  const data = await request.json();

  SecurityValidator.validateInput(data, {
    amount: { required: true, type: 'number' },
    currency: { required: false, type: 'string', pattern: /^[a-z]{3}$/ }
  });

  const stripe = new StripeService(env.STRIPE_SECRET_KEY);
  const paymentIntent = await stripe.createPaymentIntent(
    data.amount,
    data.currency || 'usd',
    data.metadata || {}
  );

  return jsonResponse({
    success: true,
    data: {
      clientSecret: paymentIntent.client_secret,
      paymentIntentId: paymentIntent.id
    }
  }, 200, origin);
}

async function handleGetPayment(request, env, origin) {
  const url = new URL(request.url);
  const paymentIntentId = url.searchParams.get('id');

  if (!paymentIntentId || !/^pi_[a-zA-Z0-9]+$/.test(paymentIntentId)) {
    throw new Error('Invalid payment intent ID');
  }

  const stripe = new StripeService(env.STRIPE_SECRET_KEY);
  const paymentIntent = await stripe.retrievePaymentIntent(paymentIntentId);

  return jsonResponse({
    success: true,
    data: {
      id: paymentIntent.id,
      amount: paymentIntent.amount / 100,
      currency: paymentIntent.currency,
      status: paymentIntent.status
    }
  }, 200, origin);
}

async function handleCreateCustomer(request, env, origin) {
  const data = await request.json();

  SecurityValidator.validateInput(data, {
    email: { required: true, type: 'string', pattern: /^[^\s@]+@[^\s@]+\.[^\s@]+$/ },
    name: { required: true, type: 'string', maxLength: 200 }
  });

  const stripe = new StripeService(env.STRIPE_SECRET_KEY);
  const customer = await stripe.createCustomer(data.email, data.name, data.metadata || {});

  return jsonResponse({
    success: true,
    data: {
      customerId: customer.id,
      email: customer.email
    }
  }, 200, origin);
}

async function handleStripeWebhook(request, env, origin) {
  await APIKeyValidator.validateWebhookSignature(request, env, 'stripe');
  
  const event = await request.json();

  switch (event.type) {
    case 'payment_intent.succeeded':
      console.log('Payment succeeded:', event.data.object.id);
      break;
    case 'payment_intent.payment_failed':
      console.log('Payment failed:', event.data.object.id);
      break;
    default:
      console.log('Unhandled event type:', event.type);
  }

  return jsonResponse({ received: true }, 200, origin);
}

async function handleRequest(request, env, ctx) {
  const origin = request.headers.get('Origin') || '';
  
  if (request.method === 'OPTIONS') {
    return new Response(null, {
      status: 204,
      headers: corsHeaders(origin)
    });
  }

  try {
    const clientIP = request.headers.get('CF-Connecting-IP') || 'unknown';
    const rateLimiter = new RateLimiter(RATE_LIMIT_MAX_REQUESTS, RATE_LIMIT_WINDOW);

    if (await rateLimiter.isRateLimited(clientIP, env)) {
      return errorResponse('Rate limit exceeded', 429, origin);
    }

    const url = new URL(request.url);
    const path = url.pathname;

    if (!path.startsWith('/webhook/')) {
      await APIKeyValidator.validateAPIKey(request, env);
    }

    if (path === '/api/send-email' && request.method === 'POST') {
      return await handleSendEmail(request, env, origin);
    }

    if (path === '/api/create-payment' && request.method === 'POST') {
      return await handleCreatePayment(request, env, origin);
    }

    if (path === '/api/get-payment' && request.method === 'GET') {
      return await handleGetPayment(request, env, origin);
    }

    if (path === '/api/create-customer' && request.method === 'POST') {
      return await handleCreateCustomer(request, env, origin);
    }

    if (path === '/webhook/stripe' && request.method === 'POST') {
      return await handleStripeWebhook(request, env, origin);
    }

    if (path === '/health' && request.method === 'GET') {
      return jsonResponse({ status: 'healthy', timestamp: Date.now() }, 200, origin);
    }

    return errorResponse('Not found', 404, origin);

  } catch (error) {
    console.error('Error:', error.message);
    return errorResponse(error.message, 500, origin);
  }
}

export default {
  async fetch(request, env, ctx) {
    return await handleRequest(request, env, ctx);
  }
};